import * as THREE from "three";
import { makeNoise3D, makeFbm } from "./noise.js";

// ---- small color helpers (work in 0..255 int rgb) ----
function lerp(a, b, t) { return a + (b - a) * t; }
function mix(c1, c2, t) {
  return [
    lerp(c1[0], c2[0], t),
    lerp(c1[1], c2[1], t),
    lerp(c1[2], c2[2], t),
  ];
}

// A believable-but-alien palette: cold teal-blue seas, ochre/green continents,
// snowy poles. Stops are [height, rgb].
const LAND_STOPS = [
  [0.00, [62, 96, 78]],   // coastal green
  [0.18, [86, 112, 66]],  // lowland
  [0.42, [120, 116, 74]], // savanna / ochre
  [0.62, [110, 92, 66]],  // foothill rock
  [0.82, [96, 86, 80]],   // mountain
  [1.00, [150, 140, 132]],// high rock
];

function rampLand(t) {
  for (let i = 0; i < LAND_STOPS.length - 1; i++) {
    const [h0, c0] = LAND_STOPS[i];
    const [h1, c1] = LAND_STOPS[i + 1];
    if (t <= h1) {
      const k = (t - h0) / (h1 - h0 || 1);
      return mix(c0, c1, Math.max(0, Math.min(1, k)));
    }
  }
  return LAND_STOPS[LAND_STOPS.length - 1][1];
}

const DEEP = [8, 26, 48];
