import puppeteer from "/tmp/node_modules/puppeteer-core/lib/esm/puppeteer/puppeteer-core.js";

const CHROME = "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome";
const logs = [];
const errors = [];

const browser = await puppeteer.launch({
  executablePath: CHROME,
  headless: "new",
  args: [
    "--no-sandbox",
    "--enable-unsafe-swiftshader",
    "--use-gl=angle",
    "--use-angle=swiftshader",
    "--window-size=1280,800",
  ],
});

const page = await browser.newPage();
await page.setViewport({ width: 1280, height: 800 });
page.on("console", (m) => logs.push(`[${m.type()}] ${m.text()}`));
page.on("pageerror", (e) => errors.push(`PAGEERROR: ${e.message}`));
page.on("requestfailed", (r) =>
  errors.push(`REQFAIL: ${r.url()} ${r.failure()?.errorText}`)
);

await page.goto("http://localhost:5173/", { waitUntil: "networkidle0", timeout: 30000 });

// Wait for loader to finish (texture bake + first frame).
await page.waitForFunction(
  () => document.getElementById("loader")?.classList.contains("done"),
  { timeout: 25000 }
).catch(() => errors.push("LOADER never reached 'done' state"));

await new Promise((r) => setTimeout(r, 1500));

// Inspect the WebGL scene state from the page.
const diag = await page.evaluate(() => {
  const canvas = document.getElementById("scene");
  const gl = canvas?.getContext("webgl2") || canvas?.getContext("webgl");
  return {
    canvasSize: canvas ? `${canvas.width}x${canvas.height}` : "no canvas",
    hasGL: !!gl,
    glVendor: gl ? gl.getParameter(gl.VERSION) : null,
    loaderDone: document.getElementById("loader")?.classList.contains("done"),
    panelHidden: document.getElementById("panel")?.classList.contains("hidden"),
  };
});

await page.screenshot({ path: "/tmp/planetfall-1.png" });

// Try clicking where a debris halo should be (probe interaction).
// Programmatically dispatch a pointer sequence at center-ish; instead, query
// the running scene isn't trivial, so click a spread of points and see if the
// panel opens.
let panelOpened = false;
const pts = [[640,400],[760,330],[520,470],[700,300],[560,360],[820,420]];
for (const [x,y] of pts) {
  await page.mouse.move(x,y);
  await page.mouse.down(); await page.mouse.up();
  await new Promise((r)=>setTimeout(r,150));
  const open = await page.evaluate(()=>!document.getElementById("panel")?.classList.contains("hidden"));
  if (open) { panelOpened = true; break; }
}
if (panelOpened) await page.screenshot({ path: "/tmp/planetfall-panel.png" });

console.log(JSON.stringify({ diag, panelOpened, errors, logTail: logs.slice(-15) }, null, 2));
await browser.close();

