import * as THREE from "three";
import { makeNoise3D, makeFbm } from "./noise.js";

// ---- small color helpers (work in 0..255 int rgb) ----
function lerp(a, b, t) { return a + (b - a) * t; }
function mix(c1, c2, t) {
  return [
    lerp(c1[0], c2[0], t),
    lerp(c1[1], c2[1], t),
    lerp(c1[2], c2[2], t),
  ];
}

// An imaginary violet world: indigo seas, deep purple continents rising to
// pale lilac highlands and frost. Stops are [height, rgb].
const LAND_STOPS = [
  [0.00, [46, 26, 64]],    // coastal deep violet
  [0.18, [74, 38, 92]],    // lowland purple
  [0.42, [104, 56, 116]],  // magenta-violet plains
  [0.62, [120, 86, 150]],  // foothill heather
  [0.82, [158, 132, 188]], // lilac highlands
  [1.00, [214, 198, 230]], // pale frost rock
];

function rampLand(t) {
  for (let i = 0; i < LAND_STOPS.length - 1; i++) {
    const [h0, c0] = LAND_STOPS[i];
    const [h1, c1] = LAND_STOPS[i + 1];
    if (t <= h1) {
      const k = (t - h0) / (h1 - h0 || 1);
      return mix(c0, c1, Math.max(0, Math.min(1, k)));
    }
  }
  return LAND_STOPS[LAND_STOPS.length - 1][1];
}

const DEEP = [18, 10, 44];     // abyssal indigo
const SHALLOW = [58, 40, 120];  // lit violet shallows
const SNOW = [228, 216, 244];   // pale lilac frost
// Bioluminescent vein glow color (bright magenta-lilac).
const GLOW = [236, 96, 220];

/**
 * Bake equirectangular color / bump / roughness maps for the planet, plus a
 * separate cloud alpha map. Heavy-ish loop (~2M px) — run behind the loader.
 */
export function generatePlanetTextures({
  seed = 7,
  width = 2048,
  height = 1024,
  seaLevel = 0.52,
} = {}) {
  const noise = makeNoise3D(seed);
  const fbm = makeFbm(noise, { octaves: 6, lacunarity: 2.1, gain: 0.5 });
  // Second noise field to vary biome tint and break up the terrain.
  const noise2 = makeNoise3D(seed * 131 + 17);
  const fbm2 = makeFbm(noise2, { octaves: 4, lacunarity: 2.3, gain: 0.55 });
  // Third field, used "ridged" to carve thin glowing veins across the surface.
  const noise3 = makeNoise3D(seed * 523 + 91);
  const fbm3 = makeFbm(noise3, { octaves: 4, lacunarity: 2.5, gain: 0.55 });

  const color = document.createElement("canvas");
  const bump = document.createElement("canvas");
  const rough = document.createElement("canvas");
  const glow = document.createElement("canvas");
  for (const c of [color, bump, rough, glow]) { c.width = width; c.height = height; }

  const cImg = color.getContext("2d").createImageData(width, height);
  const bImg = bump.getContext("2d").createImageData(width, height);
  const rImg = rough.getContext("2d").createImageData(width, height);
  const gImg = glow.getContext("2d").createImageData(width, height);
  const cD = cImg.data, bD = bImg.data, rD = rImg.data, gD = gImg.data;

  // Precompute per-column longitude sin/cos.
  const cosLon = new Float32Array(width);
  const sinLon = new Float32Array(width);
  for (let x = 0; x < width; x++) {
    const lon = (x / width) * Math.PI * 2 - Math.PI;
    cosLon[x] = Math.cos(lon);
    sinLon[x] = Math.sin(lon);
  }

  const freq = 1.8; // continent scale

  for (let y = 0; y < height; y++) {
    const lat = Math.PI / 2 - (y / height) * Math.PI;
    const cosLat = Math.cos(lat);
    const sy = Math.sin(lat);
    const latAbs = Math.abs(lat) / (Math.PI / 2); // 0 eq -> 1 pole

    for (let x = 0; x < width; x++) {
      const sx = cosLat * cosLon[x];
      const sz = cosLat * sinLon[x];

      // Base elevation in 0..1, with ridged emphasis for mountainy continents.
      let h = fbm(sx * freq, sy * freq, sz * freq);
      h = h * 0.5 + 0.5;
      // Sharpen continents a touch.
      h = Math.pow(h, 1.15);

      const biome = fbm2(sx * 2.6 + 11, sy * 2.6, sz * 2.6 - 7) * 0.5 + 0.5;

      // Irregular polar ice driven by noise so the cap edge isn't a clean line.
      const iceEdge = 0.62 + biome * 0.14;
      const ice = Math.max(0, (latAbs - iceEdge) / (1 - iceEdge));

      let r, g, b, elev, roughness;

      if (h < seaLevel) {
        // Water: depth-graded, smooth (low roughness -> sun glint).
        const depth = h / seaLevel; // 0 deep .. 1 coast
        const col = mix(DEEP, SHALLOW, Math.pow(depth, 1.4));
        r = col[0]; g = col[1]; b = col[2];
        elev = 0.30; // flat-ish sea floor on the bump map
        roughness = lerp(0.18, 0.40, depth);
      } else {
        const t = (h - seaLevel) / (1 - seaLevel); // 0 coast .. 1 peak
        let col = rampLand(t);
        // Biome tint: warmer/drier vs cooler/greener.
        const warm = [col[0] + 18, col[1] + 6, col[2] - 10];
        const cool = [col[0] - 12, col[1] + 10, col[2] + 4];
        col = mix(cool, warm, biome);
        // Snow on high peaks.
        const peakSnow = Math.max(0, (t - 0.78) / 0.22);
        col = mix(col, SNOW, Math.min(1, peakSnow));
        r = col[0]; g = col[1]; b = col[2];
        elev = 0.5 + t * 0.5;
        roughness = lerp(0.95, 0.78, t);
      }

      // Polar ice cap overlay (over land and sea alike).
      if (ice > 0) {
        const k = Math.min(1, ice * 1.3);
        r = lerp(r, SNOW[0], k);
        g = lerp(g, SNOW[1], k);
        b = lerp(b, SNOW[2], k);
        elev = lerp(elev, 0.55, k);
        roughness = lerp(roughness, 0.6, k);
      }

      const i = (y * width + x) * 4;
      cD[i] = r; cD[i + 1] = g; cD[i + 2] = b; cD[i + 3] = 255;

      const bv = elev * 255;
      bD[i] = bv; bD[i + 1] = bv; bD[i + 2] = bv; bD[i + 3] = 255;

      const rv = roughness * 255;
      rD[i] = rv; rD[i + 1] = rv; rD[i + 2] = rv; rD[i + 3] = 255;
    }
  }

  color.getContext("2d").putImageData(cImg, 0, 0);
  bump.getContext("2d").putImageData(bImg, 0, 0);
  rough.getContext("2d").putImageData(rImg, 0, 0);

  // ---- clouds: lower-res, wispy alpha from a separate fbm field ----
  const cw = 1024, ch = 512;
  const cloud = document.createElement("canvas");
  cloud.width = cw; cloud.height = ch;
  const clImg = cloud.getContext("2d").createImageData(cw, ch);
  const clD = clImg.data;
  const cn = makeNoise3D(seed * 977 + 3);
  const cfbm = makeFbm(cn, { octaves: 5, lacunarity: 2.4, gain: 0.55 });
  for (let y = 0; y < ch; y++) {
    const lat = Math.PI / 2 - (y / ch) * Math.PI;
    const cl = Math.cos(lat), sl = Math.sin(lat);
    for (let x = 0; x < cw; x++) {
      const lon = (x / cw) * Math.PI * 2 - Math.PI;
      const px = cl * Math.cos(lon), pz = cl * Math.sin(lon);
      let v = cfbm(px * 2.4, sl * 2.4, pz * 2.4) * 0.5 + 0.5;
      // Threshold into wisps.
      v = Math.max(0, (v - 0.52) / 0.48);
      v = Math.pow(v, 1.3);
      const i = (y * cw + x) * 4;
      clD[i] = 255; clD[i + 1] = 255; clD[i + 2] = 255;
      clD[i + 3] = Math.min(255, v * 255);
    }
  }
  cloud.getContext("2d").putImageData(clImg, 0, 0);

  const tex = (canvas, srgb) => {
    const t = new THREE.CanvasTexture(canvas);
    t.colorSpace = srgb ? THREE.SRGBColorSpace : THREE.NoColorSpace;
    t.anisotropy = 8;
    t.wrapS = THREE.RepeatWrapping;
    return t;
  };

  return {
    colorMap: tex(color, true),
    bumpMap: tex(bump, false),
    roughnessMap: tex(rough, false),
    cloudMap: tex(cloud, true),
  };
}

