      let r, g, b, elev, roughness;

      if (h < seaLevel) {
        // Water: depth-graded, smooth (low roughness -> sun glint).
        const depth = h / seaLevel; // 0 deep .. 1 coast
        const col = mix(DEEP, SHALLOW, Math.pow(depth, 1.4));
        r = col[0]; g = col[1]; b = col[2];
        elev = 0.30; // flat-ish sea floor on the bump map
        roughness = lerp(0.18, 0.40, depth);
      } else {
        const t = (h - seaLevel) / (1 - seaLevel); // 0 coast .. 1 peak
        let col = rampLand(t);
        // Biome tint: warmer/drier vs cooler/greener.
        const warm = [col[0] + 18, col[1] + 6, col[2] - 10];
        const cool = [col[0] - 12, col[1] + 10, col[2] + 4];
        col = mix(cool, warm, biome);
        // Snow on high peaks.
        const peakSnow = Math.max(0, (t - 0.78) / 0.22);
        col = mix(col, SNOW, Math.min(1, peakSnow));
        r = col[0]; g = col[1]; b = col[2];
        elev = 0.5 + t * 0.5;
        roughness = lerp(0.95, 0.78, t);
      }

      // Polar ice cap overlay (over land and sea alike).
      if (ice > 0) {
        const k = Math.min(1, ice * 1.3);
        r = lerp(r, SNOW[0], k);
        g = lerp(g, SNOW[1], k);
        b = lerp(b, SNOW[2], k);
        elev = lerp(elev, 0.55, k);
        roughness = lerp(roughness, 0.6, k);
      }

      // Bioluminescent veins: ridged noise → thin bright filaments. Strong on
      // land, faint shimmer on the seas, suppressed under polar frost.
      const ridge = 1 - Math.abs(fbm3(sx * 3.1 - 4, sy * 3.1, sz * 3.1 + 9));
      let vein = Math.max(0, (ridge - 0.86) / 0.14);
      vein = Math.pow(vein, 1.6);
      const seaShimmer = h < seaLevel ? 0.08 : 0.0;
      let glowAmt = Math.min(1, vein + seaShimmer) * (1 - Math.min(1, ice * 1.3));

      // Veins read brightest in low/coastal land, fading toward peaks.
      if (h >= seaLevel) {
        const t = (h - seaLevel) / (1 - seaLevel);
        glowAmt *= lerp(1.0, 0.35, Math.min(1, t));
      }

      // Tint the surface itself toward the glow color where veins are bright.
      if (glowAmt > 0.05) {
        const k = Math.min(1, glowAmt * 0.7);
        r = lerp(r, GLOW[0], k);
        g = lerp(g, GLOW[1], k);
        b = lerp(b, GLOW[2], k);
      }

      const i = (y * width + x) * 4;
      cD[i] = r; cD[i + 1] = g; cD[i + 2] = b; cD[i + 3] = 255;

      const bv = elev * 255;
      bD[i] = bv; bD[i + 1] = bv; bD[i + 2] = bv; bD[i + 3] = 255;

      const rv = roughness * 255;
      rD[i] = rv; rD[i + 1] = rv; rD[i + 2] = rv; rD[i + 3] = 255;

      // Emissive map: glow color scaled by vein strength (black elsewhere).
      const gv = Math.min(1, glowAmt);
      gD[i] = GLOW[0] * gv; gD[i + 1] = GLOW[1] * gv; gD[i + 2] = GLOW[2] * gv;
      gD[i + 3] = 255;
    }
  }

  color.getContext("2d").putImageData(cImg, 0, 0);
  bump.getContext("2d").putImageData(bImg, 0, 0);
  rough.getContext("2d").putImageData(rImg, 0, 0);
  glow.getContext("2d").putImageData(gImg, 0, 0);

  // ---- clouds: lower-res, wispy alpha from a separate fbm field ----
  const cw = 1024, ch = 512;
  const cloud = document.createElement("canvas");
  cloud.width = cw; cloud.height = ch;
  const clImg = cloud.getContext("2d").createImageData(cw, ch);
  const clD = clImg.data;
  const cn = makeNoise3D(seed * 977 + 3);
  const cfbm = makeFbm(cn, { octaves: 5, lacunarity: 2.4, gain: 0.55 });
  for (let y = 0; y < ch; y++) {
    const lat = Math.PI / 2 - (y / ch) * Math.PI;
    const cl = Math.cos(lat), sl = Math.sin(lat);
    for (let x = 0; x < cw; x++) {
      const lon = (x / cw) * Math.PI * 2 - Math.PI;
      const px = cl * Math.cos(lon), pz = cl * Math.sin(lon);
      let v = cfbm(px * 2.4, sl * 2.4, pz * 2.4) * 0.5 + 0.5;
      // Threshold into wisps.
      v = Math.max(0, (v - 0.52) / 0.48);
      v = Math.pow(v, 1.3);
      const i = (y * cw + x) * 4;
      clD[i] = 255; clD[i + 1] = 255; clD[i + 2] = 255;
      clD[i + 3] = Math.min(255, v * 255);
    }
  }
  cloud.getContext("2d").putImageData(clImg, 0, 0);

  const tex = (canvas, srgb) => {
    const t = new THREE.CanvasTexture(canvas);
    t.colorSpace = srgb ? THREE.SRGBColorSpace : THREE.NoColorSpace;
    t.anisotropy = 8;
    t.wrapS = THREE.RepeatWrapping;
    return t;
  };

  return {
    colorMap: tex(color, true),
    bumpMap: tex(bump, false),
    roughnessMap: tex(rough, false),
    cloudMap: tex(cloud, true),
  };
}

import * as THREE from "three";
import { OrbitControls } from "three/addons/controls/OrbitControls.js";
import { generatePlanetTextures } from "./planet.js";
import { makeAtmosphere } from "./atmosphere.js";
import { createDebris } from "./debris.js";

const PLANET_RADIUS = 2;

const canvas = document.getElementById("scene");
const renderer = new THREE.WebGLRenderer({ canvas, antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.05;
renderer.outputColorSpace = THREE.SRGBColorSpace;

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x02040a);

const camera = new THREE.PerspectiveCamera(
  45, window.innerWidth / window.innerHeight, 0.1, 1000
);
camera.position.set(0, 1.4, 6.5);

const controls = new OrbitControls(camera, canvas);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.enablePan = false;
controls.minDistance = 3.0;
controls.maxDistance = 9.0;
controls.rotateSpeed = 0.5;
controls.autoRotate = false;

// ---------- lighting ----------
const sun = new THREE.DirectionalLight(0xfff2e0, 2.6);
sun.position.set(5, 2.5, 4);
scene.add(sun);
scene.add(new THREE.AmbientLight(0x33405a, 0.55));
// Cool rim fill from the opposite side so the dark limb isn't pure black.
const rim = new THREE.DirectionalLight(0x2a4a7a, 0.5);
rim.position.set(-5, -1, -4);
scene.add(rim);

// ---------- starfield ----------
function makeStars() {
  const count = 2400;
  const positions = new Float32Array(count * 3);
  const colors = new Float32Array(count * 3);
  const tint = new THREE.Color();
  for (let i = 0; i < count; i++) {
    const r = 200 + Math.random() * 200;
    const u = Math.random() * 2 - 1;
    const a = Math.random() * Math.PI * 2;
    const s = Math.sqrt(1 - u * u);
    positions[i * 3] = r * s * Math.cos(a);
    positions[i * 3 + 1] = r * u;
    positions[i * 3 + 2] = r * s * Math.sin(a);
    const warm = Math.random();
    tint.setHSL(0.58 - warm * 0.12, 0.4, 0.6 + Math.random() * 0.3);
    colors[i * 3] = tint.r; colors[i * 3 + 1] = tint.g; colors[i * 3 + 2] = tint.b;
  }
  const geo = new THREE.BufferGeometry();
  geo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
  geo.setAttribute("color", new THREE.BufferAttribute(colors, 3));
  const mat = new THREE.PointsMaterial({
    size: 1.1, sizeAttenuation: true, vertexColors: true,
    transparent: true, opacity: 0.9, depthWrite: false,
  });
  return new THREE.Points(geo, mat);
}
scene.add(makeStars());

// ---------- planet ----------
const planetGroup = new THREE.Group();
scene.add(planetGroup);
planetGroup.rotation.z = 0.18; // gentle axial tilt

const { colorMap, bumpMap, roughnessMap, cloudMap } = generatePlanetTextures({
  seed: 42,
});

const planet = new THREE.Mesh(
  new THREE.SphereGeometry(PLANET_RADIUS, 128, 128),
  new THREE.MeshStandardMaterial({
    map: colorMap,
    bumpMap,
    bumpScale: 0.04,
    roughnessMap,
    metalness: 0.0,
    roughness: 1.0,
  })
);
planetGroup.add(planet);

const clouds = new THREE.Mesh(
  new THREE.SphereGeometry(PLANET_RADIUS * 1.012, 96, 96),
  new THREE.MeshStandardMaterial({
    map: cloudMap, transparent: true, depthWrite: false,
    opacity: 0.9, roughness: 1.0,
  })
);
planetGroup.add(clouds);

planetGroup.add(makeAtmosphere(PLANET_RADIUS * 1.05));

// Debris rides on the planet so it rotates in sync.
const { group: debrisGroup, pickables } = createDebris(PLANET_RADIUS);
const pickSet = new Set(pickables);
planet.add(debrisGroup);

// ---------- interaction ----------
const raycaster = new THREE.Raycaster();
const pointer = new THREE.Vector2();
let hovered = null;
let pointerDownAt = null;

function resolveAnchor(obj) {
  let o = obj;
  while (o) {
    if (pickSet.has(o)) return o;
    o = o.parent;
  }
  return null;
}

function pick(event) {
  pointer.x = (event.clientX / window.innerWidth) * 2 - 1;
  pointer.y = -(event.clientY / window.innerHeight) * 2 + 1;
  raycaster.setFromCamera(pointer, camera);
  const hits = raycaster.intersectObjects(pickables, true);
  return hits.length ? resolveAnchor(hits[0].object) : null;
}

window.addEventListener("pointermove", (e) => {
  const anchor = pick(e);
  if (anchor !== hovered) {
    hovered = anchor;
    document.body.style.cursor = anchor ? "pointer" : "default";
  }
});

// Distinguish a click from an orbit drag.
window.addEventListener("pointerdown", (e) => {
  pointerDownAt = { x: e.clientX, y: e.clientY };
});
window.addEventListener("pointerup", (e) => {
  if (!pointerDownAt) return;
  const moved = Math.hypot(e.clientX - pointerDownAt.x, e.clientY - pointerDownAt.y);
  pointerDownAt = null;
  if (moved > 6) return; // was a drag
  const anchor = pick(e);
  if (anchor) openPanel(anchor.userData.fragment);
});

// ---------- panel ----------
const panel = document.getElementById("panel");
const panelTitle = document.getElementById("panel-title");
const panelBody = document.getElementById("panel-body");
const panelFoot = document.getElementById("panel-foot");

function openPanel(frag) {
  panelTitle.textContent = frag.title;
  panelBody.textContent = frag.body;
  panelFoot.textContent = `recover with · ${frag.hint}`;
  panel.classList.remove("hidden");
}
function closePanel() { panel.classList.add("hidden"); }

document.getElementById("panel-close").addEventListener("click", closePanel);
window.addEventListener("keydown", (e) => { if (e.key === "Escape") closePanel(); });

// ---------- resize ----------
window.addEventListener("resize", () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});

// ---------- loop ----------
const clock = new THREE.Clock();
let firstFrame = true;

function animate() {
  const dt = clock.getDelta();
  const t = clock.elapsedTime;

  planet.rotation.y += dt * 0.03;
  clouds.rotation.y += dt * 0.04;

  // Pulse halos; lift & enlarge the hovered fragment.
  for (const anchor of pickables) {
    const { halo, model } = anchor.userData;
    const isHover = anchor === hovered;
    const base = 0.85 + Math.sin(t * 2 + anchor.position.x * 5) * 0.12;
    const target = isHover ? 1.5 : base;
    halo.scale.setScalar(THREE.MathUtils.lerp(halo.scale.x || 1, target, 0.15));
    halo.material.opacity = isHover ? 1.0 : 0.85;
    const ms = isHover ? 1.35 : 1.0;
    model.scale.setScalar(THREE.MathUtils.lerp(model.scale.x || 1, ms, 0.15));
    if (model.userData.pulse) {
      model.userData.pulse.material.emissiveIntensity = 1.0 + Math.sin(t * 4) * 0.6;
    }
  }

  controls.update();
  renderer.render(scene, camera);

  if (firstFrame) {
    firstFrame = false;
    document.getElementById("loader").classList.add("done");
  }
  requestAnimationFrame(animate);
}
animate();

