const { colorMap, bumpMap, roughnessMap, emissiveMap, cloudMap } =
  generatePlanetTextures({ seed: 42 });

const planet = new THREE.Mesh(
  new THREE.SphereGeometry(PLANET_RADIUS, 128, 128),
  new THREE.MeshStandardMaterial({
    map: colorMap,
    bumpMap,
    bumpScale: 0.04,
    roughnessMap,
    metalness: 0.0,
    roughness: 1.0,
    // Glowing bioluminescent veins (white carrier so the map's own color shows).
    emissiveMap,
    emissive: 0xffffff,
    emissiveIntensity: 1.6,
  })
);
planetGroup.add(planet);

const clouds = new THREE.Mesh(
  new THREE.SphereGeometry(PLANET_RADIUS * 1.012, 96, 96),
  new THREE.MeshStandardMaterial({
    map: cloudMap, transparent: true, depthWrite: false,
    color: 0xc9b8ff, // faint violet haze
    opacity: 0.6, roughness: 1.0,
  })
);
planetGroup.add(clouds);

