// ---- small color helpers (work in 0..255 int rgb) ----
function lerp(a, b, t) { return a + (b - a) * t; }
function mix(c1, c2, t) {
  return [
    lerp(c1[0], c2[0], t),
    lerp(c1[1], c2[1], t),
    lerp(c1[2], c2[2], t),
  ];
}

// A dreamy lavender ocean world: soft violet seas, a few misty pale islands.
// Low-contrast stops keep the surface calm rather than busy. [height, rgb].
const LAND_STOPS = [
  [0.00, [176, 162, 198]], // misty shore
  [0.30, [196, 184, 214]], // low island
  [0.60, [214, 204, 228]], // soft rise
  [0.85, [230, 222, 240]], // pale highland
  [1.00, [244, 240, 248]], // frost
];

function rampLand(t) {
  for (let i = 0; i < LAND_STOPS.length - 1; i++) {
    const [h0, c0] = LAND_STOPS[i];
    const [h1, c1] = LAND_STOPS[i + 1];
    if (t <= h1) {
      const k = (t - h0) / (h1 - h0 || 1);
      return mix(c0, c1, Math.max(0, Math.min(1, k)));
