        roughness = lerp(0.18, 0.40, depth);
      } else {
        const t = (h - seaLevel) / (1 - seaLevel); // 0 coast .. 1 peak
        let col = rampLand(t);
        // Biome tint: warmer/drier vs cooler/greener.
        const warm = [col[0] + 18, col[1] + 6, col[2] - 10];
        const cool = [col[0] - 12, col[1] + 10, col[2] + 4];
        col = mix(cool, warm, biome);
        // Snow on high peaks.
        const peakSnow = Math.max(0, (t - 0.78) / 0.22);
        col = mix(col, SNOW, Math.min(1, peakSnow));
        r = col[0]; g = col[1]; b = col[2];
        elev = 0.5 + t * 0.5;
        roughness = lerp(0.95, 0.78, t);
      }

      // Polar ice cap overlay (over land and sea alike).
      if (ice > 0) {
        const k = Math.min(1, ice * 1.3);
        r = lerp(r, SNOW[0], k);
        g = lerp(g, SNOW[1], k);
        b = lerp(b, SNOW[2], k);
        elev = lerp(elev, 0.55, k);
        roughness = lerp(roughness, 0.6, k);
      }

      // Bioluminescent veins: ridged noise → thin bright filaments. Strong on
      // land, faint shimmer on the seas, suppressed under polar frost.
      const ridge = 1 - Math.abs(fbm3(sx * 3.1 - 4, sy * 3.1, sz * 3.1 + 9));
      let vein = Math.max(0, (ridge - 0.86) / 0.14);
      vein = Math.pow(vein, 1.6);
      const seaShimmer = h < seaLevel ? 0.08 : 0.0;
      let glowAmt = Math.min(1, vein + seaShimmer) * (1 - Math.min(1, ice * 1.3));

      // Veins read brightest in low/coastal land, fading toward peaks.
      if (h >= seaLevel) {
        const t = (h - seaLevel) / (1 - seaLevel);
        glowAmt *= lerp(1.0, 0.35, Math.min(1, t));
      }

      // Tint the surface itself toward the glow color where veins are bright.
      if (glowAmt > 0.05) {
        const k = Math.min(1, glowAmt * 0.7);
        r = lerp(r, GLOW[0], k);
        g = lerp(g, GLOW[1], k);
        b = lerp(b, GLOW[2], k);
      }

      const i = (y * width + x) * 4;
      cD[i] = r; cD[i + 1] = g; cD[i + 2] = b; cD[i + 3] = 255;

      const bv = elev * 255;
      bD[i] = bv; bD[i + 1] = bv; bD[i + 2] = bv; bD[i + 3] = 255;

      const rv = roughness * 255;
      rD[i] = rv; rD[i + 1] = rv; rD[i + 2] = rv; rD[i + 3] = 255;

      // Emissive map: glow color scaled by vein strength (black elsewhere).
      const gv = Math.min(1, glowAmt);
      gD[i] = GLOW[0] * gv; gD[i + 1] = GLOW[1] * gv; gD[i + 2] = GLOW[2] * gv;
      gD[i + 3] = 255;
    }
  }

  color.getContext("2d").putImageData(cImg, 0, 0);
  bump.getContext("2d").putImageData(bImg, 0, 0);
  rough.getContext("2d").putImageData(rImg, 0, 0);
  glow.getContext("2d").putImageData(gImg, 0, 0);

  // ---- clouds: lower-res, wispy alpha from a separate fbm field ----
  const cw = 1024, ch = 512;
  const cloud = document.createElement("canvas");
  cloud.width = cw; cloud.height = ch;
  const clImg = cloud.getContext("2d").createImageData(cw, ch);
  const clD = clImg.data;
  const cn = makeNoise3D(seed * 977 + 3);
  const cfbm = makeFbm(cn, { octaves: 5, lacunarity: 2.4, gain: 0.55 });
  for (let y = 0; y < ch; y++) {
    const lat = Math.PI / 2 - (y / ch) * Math.PI;
    const cl = Math.cos(lat), sl = Math.sin(lat);
    for (let x = 0; x < cw; x++) {
      const lon = (x / cw) * Math.PI * 2 - Math.PI;
      const px = cl * Math.cos(lon), pz = cl * Math.sin(lon);
      let v = cfbm(px * 2.4, sl * 2.4, pz * 2.4) * 0.5 + 0.5;
      // Threshold into wisps.
      v = Math.max(0, (v - 0.52) / 0.48);
      v = Math.pow(v, 1.3);
      const i = (y * cw + x) * 4;
      clD[i] = 255; clD[i + 1] = 255; clD[i + 2] = 255;
      clD[i + 3] = Math.min(255, v * 255);
    }
  }
  cloud.getContext("2d").putImageData(clImg, 0, 0);

  const tex = (canvas, srgb) => {
    const t = new THREE.CanvasTexture(canvas);
    t.colorSpace = srgb ? THREE.SRGBColorSpace : THREE.NoColorSpace;
    t.anisotropy = 8;
    t.wrapS = THREE.RepeatWrapping;
    return t;
  };

  return {
    colorMap: tex(color, true),
    bumpMap: tex(bump, false),
    roughnessMap: tex(rough, false),
    emissiveMap: tex(glow, true),
    cloudMap: tex(cloud, true),
  };
}

