// Soft violet atmosphere — wider, gentler falloff than a hard ring.
planetGroup.add(makeAtmosphere(PLANET_RADIUS * 1.08, {
  color: new THREE.Color(0xb060ff),
  power: 2.4,
  intensity: 0.95,
